"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([["3525"],{38836(e,n,t){t.r(n),t.d(n,{metadata:()=>i,default:()=>d,frontMatter:()=>a,contentTitle:()=>s,toc:()=>c,assets:()=>h});var i=JSON.parse('{"id":"publikationen/interest-rates-not-the-money-supply","title":"Interest Rates, not the Money Supply: Towards a Non-Monetarist Interpretation of the TFEU","description":"Interest Rates, not the Money Supply","source":"@site/docs/publikationen/interest-rates-not-the-money-supply.md","sourceDirName":"publikationen","slug":"/publikationen/interest-rates-not-the-money-supply","permalink":"/dz-publikationsgraph/wiki/publikationen/interest-rates-not-the-money-supply","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"Geldpolitik","permalink":"/dz-publikationsgraph/wiki/tags/geldpolitik"},{"inline":true,"label":"EU-Recht","permalink":"/dz-publikationsgraph/wiki/tags/eu-recht"},{"inline":true,"label":"TFEU","permalink":"/dz-publikationsgraph/wiki/tags/tfeu"},{"inline":true,"label":"Monetarismus","permalink":"/dz-publikationsgraph/wiki/tags/monetarismus"},{"inline":true,"label":"EZB","permalink":"/dz-publikationsgraph/wiki/tags/ezb"}],"version":"current","frontMatter":{"title":"Interest Rates, not the Money Supply: Towards a Non-Monetarist Interpretation of the TFEU","date":"2023-01-19","authors":["Philipp Orphal","Florian Kern","Max Krah\xe9"],"cluster":"geldpolitik und anleihem\xe4rkte","tags":["Geldpolitik","EU-Recht","TFEU","Monetarismus","EZB"],"ignore":"yes","reason":"Englische Uebersetzung von zinsen-statt-geldmenge"},"sidebar":"wikiSidebar","previous":{"title":"Zurecht umstritten: Eine industriepolitische Analyse der Intel-Magdeburg Subvention","permalink":"/dz-publikationsgraph/wiki/publikationen/intel-magdeburg-analyse-de"},"next":{"title":"Introductory Statement at the ECON Committee: On Shrinking the Public Balance Sheet and the Use of Debt Sustainability Analyses","permalink":"/dz-publikationsgraph/wiki/publikationen/introductory-statement-at-the-econ-committee"}}'),r=t(74848),o=t(28453);let a={title:"Interest Rates, not the Money Supply: Towards a Non-Monetarist Interpretation of the TFEU",date:"2023-01-19",authors:["Philipp Orphal","Florian Kern","Max Krah\xe9"],cluster:"geldpolitik und anleihem\xe4rkte",tags:["Geldpolitik","EU-Recht","TFEU","Monetarismus","EZB"],ignore:"yes",reason:"Englische Uebersetzung von zinsen-statt-geldmenge"},s="BACKGROUND PAPER",h={},c=[];function l(e){let n={a:"a",h1:"h1",header:"header",li:"li",ol:"ol",p:"p",ul:"ul",...(0,o.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(n.header,{children:(0,r.jsx)(n.h1,{id:"background-paper",children:"BACKGROUND PAPER"})}),"\n",(0,r.jsx)(n.p,{children:"Interest Rates, not the Money Supply"}),"\n",(0,r.jsx)(n.p,{children:"Towards a Non-Monetarist Interpretation of the\r\nTFEU"}),"\n",(0,r.jsx)(n.p,{children:"Philipp Orphal, Florian Kern, Max Krah\xe9"}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.a,{href:"mailto:philipp.orphal@dezernatzukunft.org",children:"philipp.orphal@dezernatzukunft.org"})}),"\n",(0,r.jsx)(n.p,{children:"19.01.2023"}),"\n",(0,r.jsx)(n.p,{children:"Executive Summary"}),"\n",(0,r.jsx)(n.p,{children:'In this paper, we show that the case law on the legality of bond purchases by Eurosystem central banks is partly based on the economic theory of monetarism and, in particular, on a 1981 paper by\r\nThomas Sargent and Neil Wallace ("Some Unpleasant Monetarist Arithmetic"). However, monetarism, already controversial in the 1970s and 1980s, is now recognised as false. The assumptions on which Sargent and Wallace based thei\xdfr argument were already partially inaccurate at the time;\r\ntoday, it is generally accepted that these assumptions do not hold in reality.2 This intellectual progress should be taken into account in ongoing interpretation of the European treaties and the\r\nEuropean legal f\xfcramework.'}),"\n",(0,r.jsx)(n.p,{children:'Building on this observation, in this paper we develop an updated, "non-monetarist" interpretation of Article 123 TFEU. This interpretation deviates f\xfcrom the standards developed in previous case law\r\nin three ways:'}),"\n",(0,r.jsx)(n.p,{children:'First, the prohibition under which the European System of Central Banks may not purchase government bonds on the secondary markets under conditions which would, in practice, have an effect equivalent to that of a direct purchase of government bonds ("prohibition of transactions with\r\nequivalent effect") should be given up on.'}),"\n",(0,r.jsx)(n.p,{children:'Second, the restriction that secondary market purchases must not weaken incentives (judicially speaking, the impetus) towards sound fiscal policy ("prohibition on circumvention") should be\r\nreplaced. Instead of this restriction, the proper limiting principle is that secondary market purchases must pursue the objective of price stability and, if possible without compromising the\r\nfirst objective, support the general economic policies in the European Union. Within the purposes of Article 123 TFEU, sound public finances are only a means for achieving price stability. The focus\r\nof the interpretation should therefore be the pursuit of price stability. The general economic policy goal of sound public finances is the subject of other rules.'}),"\n",(0,r.jsx)(n.p,{children:"1"}),"\n",(0,r.jsx)(n.p,{children:"Philipp Orphal is a Ph.D. candidate at the Institute for Finance and Tax Law at the University of Hei\xdfdelberg in the fields of fiscal law"}),"\n",(0,r.jsx)(n.p,{children:"(budget law), constitutional law and European law and Policy Fellow at Dezernat Zukunft."}),"\n",(0,r.jsx)(n.p,{children:"Florian Kern is Monetary Policy Fellow at Dezernat Zukunft."}),"\n",(0,r.jsx)(n.p,{children:"Max Krah is Research Director at Dezernat Zukunft."}),"\n",(0,r.jsx)(n.p,{children:"2"}),"\n",(0,r.jsx)(n.p,{children:"Bindseil, The operational target of monetary policy and the rise and fall of reserve position doctrine, ECB Working Paper Series, No."}),"\n",(0,r.jsx)(n.p,{children:"372 / June 2004. Kern/Sigl-Gl\xfcckner/Krah, Monetary Targeting Revisited, Dezernat Zukunft, June 2022."}),"\n",(0,r.jsx)(n.p,{children:"1 of 27"}),"\n",(0,r.jsx)(n.p,{children:"Third, and on a related point, the Federal Constitutional Court of Germany (BverfG) should no longer gro\xdfund the protection of the Bundestag's budgetary right in Article 123 TFEU. The increasingly detailed measures and prohibitions built on an extensive reading of this article are detrimental to monetary policy and thus to price stability. This does not mean that the Federal Constitutional Court should give up on protecting the Bundestags budgetary sovereignty. Instead, the\r\nprotection of the Bundestags budgetary right should be carried out under the legal benchmarks actually created for this purpose: Articles 121, 125 and 126 TFEU."}),"\n",(0,r.jsx)(n.p,{children:"#MONETARY POLICY\r\n#EUROPEAN LAW\r\n#INTEREST RATE MANAGEMENT"}),"\n",(0,r.jsx)(n.p,{children:"2 of 27"}),"\n",(0,r.jsx)(n.p,{children:"Introduction and overview .............................................................................................. 4"}),"\n",(0,r.jsxs)(n.ol,{children:["\n",(0,r.jsx)(n.li,{children:"Monetarism in the institutional f\xfcramework of the Economic and Monetary\r\nUnion ........................................................................................................................... 4"}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"1.1 Sargent and Wallace: the fear of fiscal dominance . 5"}),"\n",(0,r.jsx)(n.p,{children:"1.2 Sargent and Wallace in the institutional f\xfcramework of the Economic and Monetary Union . 6"}),"\n",(0,r.jsx)(n.p,{children:"1.3 The assumptions of Sargent and Wallace do not hold in reality 9"}),"\n",(0,r.jsxs)(n.ol,{start:"2",children:["\n",(0,r.jsx)(n.li,{children:"Traces of monetarism in the case law on Article 123 TFEU ................................. 13"}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"2.1 ECJ: Three prohibitions, one thought .. 13"}),"\n",(0,r.jsx)(n.p,{children:"2.1.1 Second: No actions with an effect equivalent to primary market purchases 14"}),"\n",(0,r.jsx)(n.p,{children:"2.1.2 Third: No circumvention of the objectives of Article 123 TFEU .. 15"}),"\n",(0,r.jsx)(n.p,{children:"2.2 BVerfG: Prohibition on circumvention .. 16"}),"\n",(0,r.jsx)(n.p,{children:'2.3 Conclusion: "May contain traces of monetarism" ..17'}),"\n",(0,r.jsxs)(n.ol,{start:"3",children:["\n",(0,r.jsx)(n.li,{children:"A non-monetarist interpretation of Article 123 TFEU .......................................... 18"}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"3.1 Money supply and price stabilityfi . 18"}),"\n",(0,r.jsx)(n.p,{children:"3.2 Fiscal dominance and price stabilityfi . 19"}),"\n",(0,r.jsx)(n.p,{children:"3.3 Significance for the interpretation of Article 123 TFEU .. 21"}),"\n",(0,r.jsxs)(n.ol,{start:"4",children:["\n",(0,r.jsx)(n.li,{children:"Conclusion ................................................................................................................. 26"}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"3 of 27"}),"\n",(0,r.jsx)(n.p,{children:"Introduction and overview"}),"\n",(0,r.jsx)(n.p,{children:"In recent years, the European System of Central Banks (ESCB) has been subjected to strict limits on the purchasing of Eurozone government bonds by the European Court of Justice (ECJ) and the\r\nGerman Federal Constitutional Court (BVerfG). In particular, Article 123 of the Treaty on the\r\nFunctioning of the European Union (TFEU), which prohibits the purchase of government bonds on the primary market, was given an extensive interpretation by the courts: secondary market\r\npurchases, which are not mentioned in the text of Article 123, were also subjected to restrictive conditions in order to prevent alleged circumventions of the ban on primary market purchases.\r\nHowever, by referring in thei\xdfr case law to the historical backgro\xdfund of the regulations, which itself refers to Sargent and Wallace (1981) and monetarism, the ECJ and the BVerfG rely on an erroneous\r\nunderstanding of the instruments and causal mechanisms that central banks use to influence aggregate demand and price levels."}),"\n",(0,r.jsx)(n.p,{children:"The structure of this paper is as follows: in the first section, we examine how monetarism has influenced the institutional f\xfcramework of the Economic and Monetary Union. We provide a brief\r\nsummary of the main arguments of Sargent and Wallace's paper (1.1) and show how it shaped the rules of the Economic and Monetary Union (1.2). We then summarise how and why the core theses\r\nof thei\xdfr paper are refuted today (1.3). In the second section, we describe how the European Court of Justice and the Federal Constitutional Court have interpreted the prohibition on monetary\r\nfinancing of Member States. In doing so, we first explain the three prohibitions formulated by the\r\nECJ in its rulings in Gauweiler and Weiss (2.1), and then turn our attention towards budgetary discipline, which the BVerfG has placed at the heart of its rulings (2.2). In the third section, we\r\nconsider what consequences for the interpretation of Article 123 TFEU follow f\xfcrom the fact that the monetarist view is considered outdated among central banks practitioners and in academia today.\r\nIn particular, we show that in a non-monetarist interpretation, Article 123 TFEU need not be interpreted extensively in order to avoid inflation (3.1), nor to protect the independence of central\r\nbanks (3.2). We then explain the proposed changes in interpretation that result f\xfcrom an updated understanding of the context underpinning the jurisprudence on Article 123 TFEU (3.3). The paper\r\nends with a brief conclusion (4)."}),"\n",(0,r.jsxs)(n.ol,{children:["\n",(0,r.jsx)(n.li,{}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"Monetarism in the institutional f\xfcramework of the"}),"\n",(0,r.jsx)(n.p,{children:"Economic and Monetary Union"}),"\n",(0,r.jsx)(n.p,{children:"In this first section, we examine how monetarism the prevailing understanding of the functioning of monetary policy in the 1980s has influenced the institutional f\xfcramework of the Economic and\r\nMonetary Union. We summarise the 1981 paper by Sargent and Wallace, a touchstoffe in monetarist monetary theory (1.1), and show how it has shaped the rules of the Economic and\r\nMonetary Union (1.2). We then summarise how and why the core of this paper has been refuted today (1.3)."}),"\n",(0,r.jsx)(n.p,{children:"4 of 27"}),"\n",(0,r.jsx)(n.p,{children:"1.1 Sargent and Wallace: the fear of fiscal dominance"}),"\n",(0,r.jsx)(n.p,{children:"In todays institutional f\xfcramework, the primary task of central banks in general, and of the ECB in particular, is to control inflation. The question of what instruments and what relationship to fiscal\r\npolicy are necessary to achieve this objective has been the subject of long-running economic, political, and legal debates."}),"\n",(0,r.jsx)(n.p,{children:"One historically important contribution to these debates is the essay Some Unpleasant\r\nMonetarist Arithmetic.3 It was written by Thomas Sargent and Neil Wallace for the 1981 Fall Report of the Federal Reserve Bank of Minneapolis, shortly after the U.S. Federal Reserve (Fed) introduced\r\ncentral bank monetary targeting. In this paper, the authors argue that the central bank can control inflation only if it exercises sole control over the central bank money supply. The authors referred\r\nto this state of affairs as a system of monetary dominance. In such a system, it is impossible for the Ministry of Finance and the elected government to exert any significant influence on the central\r\nbank money supply."}),"\n",(0,r.jsx)(n.p,{children:"In thei\xdfr paper, Wallace and Sargent make three assumptions:"}),"\n",(0,r.jsxs)(n.ol,{children:["\n",(0,r.jsxs)(n.li,{children:["\n",(0,r.jsx)(n.p,{children:"Deposits that commercial banks hold at the central bank do not yield any interest. This results in an interest gain for the central bank when it acquires interest-bearing assets.\r\n(This is commonly referred to as seigniorage.)4"}),"\n"]}),"\n",(0,r.jsx)(n.li,{}),"\n",(0,r.jsx)(n.li,{}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"There is a stable and causal relationship between the money created by the central bank\r\n(the monetary base) and the price level."}),"\n",(0,r.jsx)(n.p,{children:"The yield on risk-f\xfcree government bonds, and hence the governments financing costs, depend on the supply of and demand for bonds. If the supply of risk-f\xfcree government\r\nbonds increases while demand stays the same, the price of new government bonds falls, i.e. the yields and thus the governments financing costs rise."}),"\n",(0,r.jsx)(n.p,{children:"Building on these three assumptions, Sargent and Wallace then argue that the central bank can only stabilise the price level if it has decision-making authority over the size of the government\r\ndeficit. If parliaments, acting independently and without limits, were to run bigger deficits than there is demand for risk-f\xfcree government bonds, deficits would become impossible to bond-finance (Assumption 3).5 This would leave seigniorage as the only financing option, which the central\r\nbank would be de facto obliged to provide, to preserve the risk-f\xfcree nature of government bonds.\r\nThe central bank would thus be forced to buy the bonds, putting the newly created reserves at the governments disposal. The government would then spend the money, so that the reserves end up\r\nin commercial banks accounts held at the central bank.6"}),"\n",(0,r.jsx)(n.p,{children:"3"}),"\n",(0,r.jsx)(n.p,{children:"Sargent and Wallace, Some Unpleasant Monetary Arithmetic, Federal Reserve Bank of Minneapolis Quarterly Review Vol. 5 No. 3 (Fall"}),"\n",(0,r.jsx)(n.p,{children:"4"}),"\n",(0,r.jsx)(n.p,{children:"5"}),"\n",(0,r.jsx)(n.p,{children:"1981), p. 1 ff."}),"\n",(0,r.jsx)(n.p,{children:"See ECB, What is Seignioragefi, April 7, 2017."}),"\n",(0,r.jsx)(n.p,{children:"More precisely, above a certain deficit level, the yields that would be required to sell the desired amount of government bonds would"}),"\n",(0,r.jsx)(n.p,{children:"exceed the gro\xdfwth rate of the economy. If this remained the case over the longer term, a debt spiral would result, making it impossible"}),"\n",(0,r.jsx)(n.p,{children:"to finance further deficits through bonds (see Blanchard, Public Debt and Low Interest Rates, American Economic Review, 109(4), 2019)."}),"\n",(0,r.jsx)(n.p,{children:"6"}),"\n",(0,r.jsx)(n.p,{children:"For example, the Bundestag could finance the construction of an expensive statue. In order to do so, it would need to hire a contractor."}),"\n",(0,r.jsx)(n.p,{children:"The construction company has an account with Deutsche Bank. Accordingly, a transfer would be made f\xfcrom the central bank account of"}),"\n",(0,r.jsx)(n.p,{children:"the German government to the central bank account of Deutsche Bank, which would credit the balance to the construction company."}),"\n",(0,r.jsx)(n.p,{children:"5 of 27"}),"\n",(0,r.jsx)(n.p,{children:"Since the central bank deposits of commercial banks do not yield any interest in the Sargent and\r\nWallace model (Assumption 1), this would not result in any interest costs for the central bank; the spending plans of the state could therefore be accommodated without any further impact on the\r\nbudget (no need for new taxes, no new interest costs for the central bank and hence no reduction in seigniorage profit transfers). According to Assumption 2, however, these new balances would\r\nraise the general price level."}),"\n",(0,r.jsx)(n.p,{children:"If parliaments were able to determine thei\xdfr budgets independently of the central bank, a state of fiscal dominance would therefore prevail: the price level would be determined indirectly by\r\nbudget legislation; the central bank would always have to follow suit and close any gaps between deficits and the demand for government bonds through seigniorage. Since seigniorage increases\r\nthe money supply, which in turn increases the price level, the central bank would not be able to ensure price stability."}),"\n",(0,r.jsx)(n.p,{children:"The central bank could only ensure price stability in a regime of monetary dominance, in which it provides just enough money to keep the gro\xdfwth in lending volumes to a desired level, and thus\r\ngro\xdfwth in the price level (via the money creation multiplier) stable. Parliaments would then be able to finance deficits only to the extent dictated by the sum of the seigniorage independently set by\r\nthe central bank (which is paid into the budget) and the demand for government bonds (which, according to Assumption 3, determines the cost of financing and thus sets a limit on the ability to\r\nfinance deficits)."}),"\n",(0,r.jsx)(n.p,{children:"1.2 Sargent and Wallace in the institutional f\xfcramework of the Economic and Monetary"}),"\n",(0,r.jsx)(n.p,{children:"Union"}),"\n",(0,r.jsx)(n.p,{children:"This notion of controlling inflation through controlling the central bank money supply took on a central role in the establishment of the European Economic and Monetary Union in the Maastricht\r\nTreaty of February 7, 1992. There was significant concern about a regime of fiscal dominance, in which monetary stability would be threatened by deficits that required the use of seigniorage.7\r\nOn October 27, 1990, the Economic and Financial Affairs Council (Ecofin), in which the finance ministers of the Member States meet, presented the so-called Carli Report under the thenChairman, Italian Finance Minister Carli, which described the institutional conditions that the\r\nfinance ministers believed were necessary for a monetary union to succeed. The report shows that\r\nEcofin considered the money supply to be an instrument of monetary policy and wanted to allow purchases of government bonds only for the purpose of controlling the money supply."}),"\n",(0,r.jsx)(n.p,{children:"7"}),"\n",(0,r.jsx)(n.p,{children:'See e.g. Economic and Monetary Union, Bulletin of the European Communities, Supplement 2/91, p. 24, where the Commission expresses its concern about "pressure for monetary accommodation"; see also Committee for the Study of Economic and Monetary Union:'}),"\n",(0,r.jsx)(n.p,{children:"Report on economic and monetary union in the European Community, 17.4.1989 (the so-called Delors Report), para. 30 at p. 19 and para."}),"\n",(0,r.jsx)(n.p,{children:"59 at p. 35 f."}),"\n",(0,r.jsx)(n.p,{children:"6 of 27"}),"\n",(0,r.jsx)(n.p,{children:"Box 1: Extract f\xfcrom the Report of the Economic and Financial Affairs Council to the\r\nCouncil of Heads of State and Government of the Union, October 27, 1990 (Carli Report)"}),"\n",(0,r.jsx)(n.p,{children:"According to the view shared by all the Member States, except the United Kingdom, the final stage of economic and monetary union will be achieved through the transfer of national powers to a\r\nmonetary authority responsible for conducting monetary policy. The aim of that policy will be to ensure that the purchasing power of the currency remains stable; measures to support the\r\npolicy for boosting income and employment would not be ruled out but, in the event of a conflict of interests, price stability would have to take precedence."}),"\n",(0,r.jsx)(n.p,{children:"A monetary policy of this nature presupposes that the authority conducting it would enjoy complete independence and absolute autonomy. The money supply and interest rates\r\nare monetary policy instruments and the authority responsible for maintaining price stability would have to be f\xfcree to decide on thei\xdfr use."}),"\n",(0,r.jsx)(n.p,{children:"This has the following implications:"}),"\n",(0,r.jsx)(n.p,{children:"(1) Budget deficits could not be financed, either directly or indirectly through money creation.\r\nThe central banks would have to be barred f\xfcrom granting governments advances or subsidies.\r\nPurchases of government securities could be permitted exclusively on the initiative of the of money\r\ncentral in circulation. Similarly, the commercial banks could not be obliged to purchase securities or to\r\nfinance governments in any other way;"}),"\n",(0,r.jsx)(n.p,{children:"regulate"}),"\n",(0,r.jsx)(n.p,{children:"amount"}),"\n",(0,r.jsx)(n.p,{children:"banks"}),"\n",(0,r.jsx)(n.p,{children:"solely"}),"\n",(0,r.jsx)(n.p,{children:"order"}),"\n",(0,r.jsx)(n.p,{children:"and"}),"\n",(0,r.jsx)(n.p,{children:"the"}),"\n",(0,r.jsx)(n.p,{children:"to"}),"\n",(0,r.jsx)(n.p,{children:"in"}),"\n",(0,r.jsx)(n.p,{children:"(2) No Member State could benefit f\xfcrom the guarantee afforded by other Member States or by the\r\nCommunity budget in respect of operations to finance its budget deficit;"}),"\n",(0,r.jsx)(n.p,{children:"(3) Excessive deficits would not be permitted. A clear definition of what constitutes an excessive deficit has yet to be agreed on, but work is in progress with a view to reaching a consensus on this\r\npoint. []"}),"\n",(0,r.jsx)(n.p,{children:'The Maastricht Treaty codified these considerations in Article 104 of the "Treaty establishing the\r\nEuropean Community" (TEC). This article was transferred, with its wording unchanged, to Article\r\n123 of the "Treaty on the Functioning of the European Union" (TFEU) by the Lisbon Treaty of\r\nDecember 13, 2007:8'}),"\n",(0,r.jsx)(n.p,{children:'"(1) Overdraft facilities or any other type of credit facility with the European Central Bank or with the central banks of the Member States [...] in favour of [...] central governments, regional or local\r\nauthorities, [or] other bodies governed by public law [...] shall be prohibited, as shall the purchase directly f\xfcrom them by the European Central Bank or national central banks of debt\r\ninstruments."'}),"\n",(0,r.jsx)(n.p,{children:"8"}),"\n",(0,r.jsx)(n.p,{children:"In the Treaty of Nice of February 26, 2001, it was (also with the wording unchanged) moved to Article 101 TEC."}),"\n",(0,r.jsx)(n.p,{children:"7 of 27"}),"\n",(0,r.jsx)(n.p,{children:'The first implication of the Carli Report is that it was intended to ensure that overdraft or other lending activities or the purchase of government bonds by central banks should only take place\r\n"exclusively on the initiative of the central banks and to regulate the amount of money in circulation." These actions were explicitly not to be used to finance the deficits of Member States.'}),"\n",(0,r.jsx)(n.p,{children:"At the same time, the reference to regulating the money supply reveals the underlying assumption that inflation depends on the money supply, i.e. that monetary measures such as lending to\r\ngovernments or the purchase of bonds by central banks if carried out in amounts other than those intended by the central bank would automatically result in inflation risks. This would run\r\ncounter to the objective of price stability, which forms the basis for all rules governing the functioning of the Economic and Monetary Union (Article 3 TEU and 119 TFEU, formerly Article 3a\r\nTEC-Maastricht and Article 4 TEC-Nice, respectively). In this vein Advocate General Juliane Kokott explained, in her Opinion before the ECJ f\xfcrom March 2022, that its [the prohibition of monetary\r\nfinancings] purpose is, on the one hand, to prevent the governments of the Member States f\xfcrom increasing the monetary base through thei\xdfr fiscal policy decisions and thereby possibly influencing\r\nthe monetary policy of the ESCB.9"}),"\n",(0,r.jsx)(n.p,{children:'Based on this understanding, the additional "disciplining effect" of market interest rates on the management of public finances through the prohibition on central bank financing would also, in\r\nparticular, have the effect of preventing government debt f\xfcrom being issued in volumes exceeding the market demand for government bonds. As a reminder, according to Sargent and Wallace, a\r\ndeficit larger than this market demand would automatically result in central bank money creation, and thus an increase in the money supply and ultimately inflation.'}),"\n",(0,r.jsx)(n.p,{children:'In this narrative, Article 124 TFEU,10 too, which prohibits the privileged access of the public sector to financial institutions, is also intended to prevent an increase in the money supply, in this case\r\nvia money creation by commercial banks, in addition to the desired disciplining effect of the markets, as can be seen in the first implication of the Carli Report. As late as October 2020, Isabel\r\nSchnabel declared, in the language of Sargent and Wallace: "The euro has been built on the principle of monetary dominance."11'}),"\n",(0,r.jsx)(n.p,{children:"9"}),"\n",(0,r.jsx)(n.p,{children:"Opinion of 31.3.2022, C-45/21 - Banka Slovenije, ECLI:EU:C:2022:241, para. 129. The passage continues: On the other hand, however, by"}),"\n",(0,r.jsx)(n.p,{children:"precluding national governments f\xfcrom having extensive access to the resources of the NCBs, that prohibition is also intended to prevent"}),"\n",(0,r.jsx)(n.p,{children:"governments f\xfcrom undermining the financial independence of thei\xdfr central bank in that way. We pick up on this intent, i.e. the protection of central bank independence, in Section 3.2 below."}),"\n",(0,r.jsx)(n.p,{children:"10"}),"\n",(0,r.jsx)(n.p,{children:"At the time, Article 104a TEC."}),"\n",(0,r.jsx)(n.p,{children:"11"}),"\n",(0,r.jsx)(n.p,{children:"Schnabel, The shadow of fiscal dominance: Misconceptions, perceptions and perspectives, SUERF Policy Note No. 198, October 2020."}),"\n",(0,r.jsx)(n.p,{children:"8 of 27"}),"\n",(0,r.jsx)(n.p,{children:"1.3 The assumptions of Sargent and Wallace do not hold in reality"}),"\n",(0,r.jsx)(n.p,{children:"We have explained elsewhere that the balances of commercial banks held at the central bank earn interest today (contrary to Assumption 1) and that there is no stable money multiplier (contrary to\r\nAssumption 2). If the Fed financed U.S. congressional deficits today, this would increase the Fed's interest expense (and thus reduce the central bank profit that gets transferred to Congress) in the\r\nsame amount as the reduction in interest costs of Congress.12 A central bank paying interest on reserve balances therefore cannot be abused for the generation of seigniorage. More\r\nfundamentally, in the absence of a stable money multiplier, there is no reason to assume that the type of financing (purchase of bonds by the central bank or purchase of bonds by\r\nmarket participants) would have a decisive impact on aggregate demand and the price level. This observation alone implies that the danger described by Sargent and Wallace is not a\r\ndanger we need to worry about today."}),"\n",(0,r.jsx)(n.p,{children:"The ECB, too, no longer considers an increase or decrease in the money supply to be a monetary policy instrument for managing demand (and thus inflation, since price increases are caused by a\r\nstronger rise in demand compared to supply). Instead, the ECB, like other central banks, uses"}),"\n",(0,r.jsx)(n.p,{children:"a."}),"\n",(0,r.jsx)(n.p,{children:"b."}),"\n",(0,r.jsx)(n.p,{children:"c."}),"\n",(0,r.jsx)(n.p,{children:"short-term interest rates,"}),"\n",(0,r.jsx)(n.p,{children:"forward guidance,13 i.e., the expression of expectations regarding the future course of short-term interest rates, as well as"}),"\n",(0,r.jsx)(n.p,{children:"purchase programmes aimed at reducing so-called term premia, i.e. the deviation of actual market interest rates f\xfcrom expected short-term interest rates over time.14"}),"\n",(0,r.jsx)(n.p,{children:'Whereas the Carli Report stated that "the (central bank) money supply and interest rates are monetary policy instruments" (see Box 1 above), the ECB\'s updated monetary policy strategy no\r\nlonger makes any reference to the central bank money supply or to money supply management.15'}),"\n",(0,r.jsx)(n.p,{children:'This view is shared by the Bundesbank.16 At his presentation on "The Eurosystem\'s New Monetary\r\nPolicy Strategy" in Berlin on November 25, 2021, the Chief Economist of the Bundesbank, Jens\r\nUlbrich, presented the following slide on this topic (Figure 1), which describes the effect of interest rates (as\r\nmonetary policy instruments on both short-term and long-term nominal reflected in bond yields).'}),"\n",(0,r.jsx)(n.p,{children:"12"}),"\n",(0,r.jsx)(n.p,{children:"Monetary financing could result in a marginal difference in financing costs equal to the spread between Treasury refinancing costs"}),"\n",(0,r.jsx)(n.p,{children:"(T-bills) and the expectations of central bank interest rate changes f\xfcrom overnight indexed swaps. This difference amounts to only a few"}),"\n",(0,r.jsx)(n.p,{children:"basis points."}),"\n",(0,r.jsx)(n.p,{children:"13"}),"\n",(0,r.jsx)(n.p,{children:"No. 8 of the Statement on the ECB's monetary policy strategy and An overview of the ECB's monetary policy strategy, Chapter 3, ECB"}),"\n",(0,r.jsx)(n.p,{children:"Economic Bulletin 5/2021, August 5, 2021."}),"\n",(0,r.jsx)(n.p,{children:"14"}),"\n",(0,r.jsx)(n.p,{children:"cf. Kern, Das Anti-Fragmentierungstool des Eurosystems verstndlich erkl\xe4rt, Geldbrief, July 7, 2022. (DE)"}),"\n",(0,r.jsx)(n.p,{children:"15"}),"\n",(0,r.jsx)(n.p,{children:"See references in footnote 11."}),"\n",(0,r.jsx)(n.p,{children:"16"}),"\n",(0,r.jsx)(n.p,{children:"See Deutsche Bundesbank, The Role of Banks, Non-Banks and the Central Bank in the Money Creation Process, Monthly Report April"}),"\n",(0,r.jsx)(n.p,{children:"2017, pp. 15 ff. The Bundesbank explains here why the notion of a money creation multiplier is misleading. However, in a regime of"}),"\n",(0,r.jsx)(n.p,{children:"central bank money supply control, the existence of a money creation multiplier is necessary in order to establish any causal relationship"}),"\n",(0,r.jsx)(n.p,{children:"at all between the central bank money supply and aggregate demand, through which monetary policy ultimately affects the price level."}),"\n",(0,r.jsx)(n.p,{children:"9 of 27"}),"\n",(0,r.jsx)(n.p,{children:"Long-term nominal interest rate"}),"\n",(0,r.jsx)(n.p,{children:"= Short-term nominal\r\ninterest rate"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsxs)(n.li,{children:["\n",(0,r.jsx)(n.p,{children:"Expected short-term"}),"\n"]}),"\n",(0,r.jsxs)(n.li,{children:["\n",(0,r.jsx)(n.p,{children:"Term premium"}),"\n"]}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"interest rates"}),"\n",(0,r.jsx)(n.p,{children:"Policy rates"}),"\n",(0,r.jsx)(n.p,{children:"Forward Guidance"}),"\n",(0,r.jsx)(n.p,{children:"Purchase programme"}),"\n",(0,r.jsx)(n.p,{children:"Interest lower bound"}),"\n",(0,r.jsx)(n.p,{children:"Figure 1:"}),"\n",(0,r.jsx)(n.p,{children:'Effects of Monetary Policy Instruments; Source: Recreated excerpt f\xfcrom the presentation "The Eurosystem\'s New Monetary\r\nPolicy Strategy" by Jens Ulbrich, Nov. 25, 2021'}),"\n",(0,r.jsx)(n.p,{children:"Parallel developments took place in the USA. Starting in 2008, the Fed implemented a so-called ample reserve regime, which it reaffirmed in 2019 for the longer term.17 Under this regime, interest\r\nrates are not controlled indirectly, via varying the money supply, but explicitly, i.e. via setting the amount of interest paid by the central bank in remuneration for commercial bank deposits."}),"\n",(0,r.jsx)(n.p,{children:"The Eurosystem has long used the same approach to manage interest rates. In such a system of monetary policy implementation, the size of the monetary base is irrelevant.18"}),"\n",(0,r.jsx)(n.p,{children:"Accordingly, the consensus view in economics no longer regards a change in the money supply as a driver of inflation.19 This is because when the market is saturated with central bank money, the\r\ncentral bank influences aggregate demand and thus the price level by changing interest rates.20 In such an implementation regime, the interest rate on the interbank money market is no longer\r\ndetermined by demand and supply, but by arbitrage (no money market participant would grant a loan at conditions that are less favourable than what they would receive at the central bank).21"}),"\n",(0,r.jsx)(n.p,{children:"17"}),"\n",(0,r.jsx)(n.p,{children:"See Federal Reserve, Statement Regarding Monetary Policy Implementation and Balance Sheet Normalization, January 30, 2019."}),"\n",(0,r.jsx)(n.p,{children:"18"}),"\n",(0,r.jsx)(n.p,{children:"As long as it does not fall below a minimum level at which point central bank money would become so scarce that commercial banks"}),"\n",(0,r.jsx)(n.p,{children:"would pay more for reserves in the money market than they receive f\xfcrom the central bank. Kern/Sigl-Gl\xfcckner/Krah, Monetary Targeting revisited, pp. 16."}),"\n",(0,r.jsx)(n.p,{children:"19"}),"\n",(0,r.jsx)(n.p,{children:"See Kern/Krah, Der leise Tod der Geldmengensteuerung: Ende eines Irrwegs, Geldbrief, April 7, 2022. (DE)"}),"\n",(0,r.jsx)(n.p,{children:"20"}),"\n",(0,r.jsx)(n.p,{children:"See Sigl-Gl\xfcckner, Der Zinshammer Wie Zentralbanken Inflation bekmpfen, Geldbrief, Jan. 28, 2022. (DE)"}),"\n",(0,r.jsx)(n.p,{children:"21"}),"\n",(0,r.jsx)(n.p,{children:"See in detail berg/Corsi/Gro\xdfssmann-Wirth/Hudepohl/Mudde/Rosolin/Schobert, ECB Occasional Paper Series No. 282 (September 2021)"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsx)(n.li,{children:"Demand for central bank reserves and monetary policy implementation f\xfcrameworks: the case of the Eurosystem, pp. 8 and 11."}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"10 of 27"}),"\n",(0,r.jsx)(n.p,{children:"The third key assumption of Sargent and Wallace does not hold either. The yields on government bonds and hence, the financing costs of states with monetary sovereignty derive f\xfcrom"}),"\n",(0,r.jsx)(n.p,{children:"expectations about the future development of policy interest rates,"}),"\n",(0,r.jsx)(n.p,{children:"term premia (deviations f\xfcrom interest rate expectations),22 as well as"}),"\n",(0,r.jsxs)(n.ol,{start:"3",children:["\n",(0,r.jsx)(n.li,{children:"balance sheet costs23 (regulatory costs for investment banks that result f\xfcrom holding riskf\xfcree government bonds)."}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"If a government runs higher deficits, i.e. increases the supply of government bonds, this will only lead to higher yields if one of these three variables increases at the same time.24 Since additional\r\ndeficits (i.e. a higher supply of bonds) do not automatically lead to higher expectations regarding the future development of policy rates, higher term premia i.e. deviations of actual interest rates\r\nf\xfcrom expected future policy rates or increased balance sheet costs, they do not automatically imply higher yields.25"}),"\n",(0,r.jsx)(n.p,{children:"The prohibition on monetary financing in today's Article 123 TFEU and the prohibition on privileged access to financial institutions in today's Article 124 TFEU were thus built on assumptions that we\r\nnow know to be flawed."}),"\n",(0,r.jsx)(n.p,{children:"fi"}),"\n",(0,r.jsx)(n.p,{children:"The deposit rate is not zero (Assumption 1), but is used by the central bank specifically to steer interbank rates."}),"\n",(0,r.jsx)(n.p,{children:'There is no stable relationship between the money supply and the price level (Assumption\r\n2). "Monetary" measures, i.e. measures affecting the money supply, do not automatically lead to inflation.'}),"\n",(0,r.jsx)(n.p,{children:"The financing costs for government bonds are not mainly driven by the demand and supply of bonds (Assumption 3), but by expected future policy rates for the remaining term\r\nof the respective bond, by the term premium and by balance sheet costs for investors, none of which necessarily change with higher government debt or deficits.26"}),"\n",(0,r.jsx)(n.p,{children:"As a consequence, fiscal dominance does not make it impossible for the central bank to control the price level. The monetary financing of government spending does not have inflationary effects\r\nwhen it has any because of the concomitant increase in the money supply."}),"\n",(0,r.jsx)(n.p,{children:"22"}),"\n",(0,r.jsx)(n.p,{children:"See Kern, Finanzmrkte sind keine Luftballons Wie sich die Geldpolitik auf Vermgenspreise auswirkt, Geldbrief, Sept. 14, 2021 (DE)."}),"\n",(0,r.jsx)(n.p,{children:"See also Bundesrepublik Deutschland Finanzagentur GmbH, Understanding Federal Securities: How does a bond workfi."}),"\n",(0,r.jsx)(n.p,{children:"23"}),"\n",(0,r.jsx)(n.p,{children:"Until the financial crisis, the yield on safe assets was usually explained as the sum of average expected short-term interest rates and a"}),"\n",(0,r.jsx)(n.p,{children:"term premium, which represented deviations f\xfcrom expectations, cf. Kim/Orphanides, The bond market term premium: what is it, and"}),"\n",(0,r.jsx)(n.p,{children:"how can we measure itfi, BIS Quarterly Review, June 2007, p. 27 ff. Since the introduction of the leverage ratio in Basel III, which sets a"}),"\n",(0,r.jsx)(n.p,{children:"debt ceiling for investment banks acting as market makers as marginal investors in the government bond market and whose funding"}),"\n",(0,r.jsx)(n.p,{children:"costs are therefore reflected in market prices, balance sheet costs have also been cited in the literature. The balance sheet costs correspond approximately to the pro rata equity costs that investment banks use to calculate holding a given position. cf. Fleckenstein/"}),"\n",(0,r.jsx)(n.p,{children:"Longstaff, Shadow Funding Costs: Measuring the Cost of Balance Sheet Constraints (2018), NBER Working Paper Series (Working Paper"}),"\n",(0,r.jsx)(n.p,{children:"24224)."}),"\n",(0,r.jsx)(n.p,{children:"24"}),"\n",(0,r.jsx)(n.p,{children:"If yields were to rise above the sum of interest rate expectations, term premiums, and balance sheet costs, banks could buy government"}),"\n",(0,r.jsx)(n.p,{children:"bonds and sell an interest rate swap in which they pay fixed rates and receive floating rates, earning an arbitrage profit equal to the"}),"\n",(0,r.jsx)(n.p,{children:"difference."}),"\n",(0,r.jsx)(n.p,{children:"25"}),"\n",(0,r.jsx)(n.p,{children:"If, for example, a parliament were to adopt a deficit-financed investment program in an economic crisis with high unemployment, this"}),"\n",(0,r.jsx)(n.p,{children:"does not necessarily have an inflationary effect, since it will mainly mobilise unused economic capacity. In this case, the central bank may"}),"\n",(0,r.jsx)(n.p,{children:"not raise interest rates despite higher public spending and government bond yields would not respond to the higher supply of government bonds."}),"\n",(0,r.jsx)(n.p,{children:"26"}),"\n",(0,r.jsx)(n.p,{children:"See footnote 25 above."}),"\n",(0,r.jsx)(n.p,{children:"11 of 27"}),"\n",(0,r.jsx)(n.p,{children:"Obviously, this does not imply that there is no place for fiscal rules. Deficits usually have an impact on aggregate demand, which could have an inflationary effect (and would therefore weaken the\r\nmonetary value of the single currency)."}),"\n",(0,r.jsx)(n.p,{children:"However, the inflationary effect is not a question of the quantity of central bank money. Instead, it is driven by the volume of credit creation or destruction, the composition of public spending, the\r\nelasticity of supply, possible reactions in financial markets, as well as a number of other factors.\r\nIndeed, even large government deficits may not have an impact on demand (and thus remain inflation-neutral), as when a Member State assumes the debts of financial institutions during a\r\nfinancial crisis.27"}),"\n",(0,r.jsx)(n.p,{children:"Since bank bailouts can be simultaneously deficit-increasing and (central bank) money supplyincreasing as well as financial stability-enhancing and inflation-neutral, restricting the size of public deficits or interpreting the prohibition on central bank bond purchasing extensively may run\r\ncounter to the objective of ensuring price stability in critical situations. This example demonstrates the dangers of looking only at the money supply or the size of deficits to safeguard price stability.\r\nDoing so would be problematic with respect to the goal of price stability, might result in excessive restrictions on Member States' budgetary sovereignty, and undermine the democratic legitimacy\r\nof the overall f\xfcramework of monetary and economic governance."}),"\n",(0,r.jsx)(n.p,{children:"27 The assumption of debt - or rather the payment of creditors by the state - does not create new demand, but instead satisfies alreadyexisting demand. It could be countered that this prevents defaults on payment, which themselves would have slowed demand. Such"}),"\n",(0,r.jsx)(n.p,{children:"situations, however, have only a very indirect connection with the intended purpose of limiting the money supply."}),"\n",(0,r.jsx)(n.p,{children:"12 of 27"}),"\n",(0,r.jsx)(n.p,{children:"Traces of monetarism in the case law on Article 123 TFEU"}),"\n",(0,r.jsx)(n.p,{children:"As a general principle, the interpretation of legal concepts cannot be delegated to the respective disciplines f\xfcrom which the concepts originate, but is instead determined through jurisprudence. In\r\norder to preserve the underlying purposes of a legal text and to avoid exceeding the expertise of the respective decision-makers, the interpretation of legal standards cannot depend solely on the\r\noften disputed state of the respective discipline at the time of enactment, of application by the addressees, or of interpretation during legal examination.28 The problem of legal interpretation\r\nbecomes truly complex when certain economic ideas are themselves written into the legal code.29\r\nHowever, on the basis of implementing the individual provisions (Articles 120-126 TFEU) for the purposes listed in Article 119 TFEU, it seems methodologically important to identify the area where\r\nthe relevant factual knowledge has developed, and to attempt possible translations into the teleological-legal interpretation of the provisions. Therefore, in this section we will first look at how\r\nthe ECJ (2.1) and the BVerfG (2.2) have interpreted the prohibition on monetary financing, in order to then, in section 3, draw conclusions for interpretation f\xfcrom the amended understanding of\r\nmonetary policy."}),"\n",(0,r.jsx)(n.p,{children:"2.1 ECJ: Three prohibitions, one thought"}),"\n",(0,r.jsx)(n.p,{children:"In its rulings on Outright Monetary Transactions (OMT; Gauweiler) and the Expanded Asset\r\nPurchase Programme/Public Sector Purchase Programme (EAPP/PSPP; Weiss), the ECJ developed a three-step legal compliance test for central banks' bond purchasing programmes:"}),"\n",(0,r.jsx)(n.p,{children:"First, primary market purchases are completely prohibited under Article 123 TFEU30 (direct prohibition);"}),"\n",(0,r.jsx)(n.p,{children:'second, "the ESCB does not have authority to purchase government bonds on secondary markets under conditions which would, in practice, mean that its action has an effect equivalent to that of a direct purchase of government bonds [...] thereby undermining the\r\neffectiveness of the prohibition in Article 123(1) TFEU"31 (prohibition on transactions with equivalent effect); and'}),"\n",(0,r.jsx)(n.p,{children:'third and finally, "purchases made on the secondary market may not be used to circumvent the objective of Article 123 TFEU"32 (prohibition on circumvention).'}),"\n",(0,r.jsx)(n.p,{children:"In the following sections, we will look at the second (2.1.1) and third prohibitions (2.1.2), each of which also prohibits certain bond purchases in secondary markets."}),"\n",(0,r.jsx)(n.p,{children:"28"}),"\n",(0,r.jsx)(n.p,{children:"On the importance of new economic findings in the interpretation of constitutional law BVerfGE 79, 311 (336 ff.); BVerfGE 119, 96 Rn. 127"}),"\n",(0,r.jsx)(n.p,{children:"ff.; see also Kirchhof, Die Allgemeinhei\xdft des Gesetzes, p. 580 f. with further references (DE)."}),"\n",(0,r.jsx)(n.p,{children:"29"}),"\n",(0,r.jsx)(n.p,{children:"For interesting discussions around this issue, see the judgments cited in footnote 28 above."}),"\n",(0,r.jsx)(n.p,{children:"30"}),"\n",(0,r.jsx)(n.p,{children:"ECJ judgment of 16.6.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:400, para. 94 f.; ECJ judgment of 11.12.2018 - C-493/17 - Weiss,"}),"\n",(0,r.jsx)(n.p,{children:"ECLI:EU:C:2018:1000, para. 102."}),"\n",(0,r.jsx)(n.p,{children:"31"}),"\n",(0,r.jsx)(n.p,{children:"ECJ"}),"\n",(0,r.jsx)(n.p,{children:"judgment of 16.6.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:400, para. 97; ECJ"}),"\n",(0,r.jsx)(n.p,{children:"judgment of 11.12.2018 - C-493/17 - Weiss,"}),"\n",(0,r.jsx)(n.p,{children:"ECLI:EU:C:2018:1000, para. 106."}),"\n",(0,r.jsx)(n.p,{children:"32"}),"\n",(0,r.jsx)(n.p,{children:"ECJ judgment of 16.6.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:400, para. 101."}),"\n",(0,r.jsx)(n.p,{children:"13 of 27"}),"\n",(0,r.jsx)(n.p,{children:"2.1.1 Second: No actions with an effect equivalent to primary market purchases"}),"\n",(0,r.jsx)(n.p,{children:'The second prohibition established by the ECJ is that the ESCB "does not have authority to purchase government bonds on secondary markets under conditions which would, in practice,\r\nmean that its action has an effect equivalent to that of a direct purchase of government bonds [...] thereby undermining the effectiveness of the prohibition in Article 123(1) TFEU".33 An action would\r\nhave this "effect equivalent to that of a [prohibited] direct purchase of government bonds [...] if the potential purchasers of government bonds [...] knew for certain that the ESCB was going to\r\npurchase those bonds within a certain period and under conditions allowing those market operators to act, de facto, as intermediaries for the ESCB for the direct purchase of those bonds\r\n[...]".34 In this regard, the ECJ stated that "safeguards" were needed in order to "prevent the conditions of issue of government bonds f\xfcrom being distorted by the certainty that those bonds\r\nwill be purchased by the ESCB after thei\xdfr issue".35 In its later Weiss ruling, the ECJ further specified this condition to the effect that the safeguards are "specifically to prevent private operators f\xfcrom\r\npredicting with certainty whether particular bonds will in fact be purchased on the secondary markets under the PSPP."36'}),"\n",(0,r.jsx)(n.p,{children:"Conclusion: In terms of its content, this interpretation does not focus on the purpose or historical origin of the provision, but rather on the wording of the prohibition on primary purchases, which\r\nin this interpretation may not be undermined by any parallel actions."}),"\n",(0,r.jsx)(n.p,{children:"33"}),"\n",(0,r.jsx)(n.p,{children:"34"}),"\n",(0,r.jsx)(n.p,{children:"ECJ judgment of 16.6.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:400, para. 104; ECJ judgment of 11.12.2018 - C-493/17 - Weiss,"}),"\n",(0,r.jsx)(n.p,{children:"ECLI:EU:C:2018:1000, para. 110."}),"\n",(0,r.jsx)(n.p,{children:"35"}),"\n",(0,r.jsx)(n.p,{children:"ECJ judgment of 16.6.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:400, para. 107."}),"\n",(0,r.jsx)(n.p,{children:"36"}),"\n",(0,r.jsx)(n.p,{children:"ECJ judgment of 11.12.2018 - C-493/17 - Weiss, ECLI:EU:C:2018:1000, paras 117, 127."}),"\n",(0,r.jsx)(n.p,{children:"14 of 27"}),"\n",(0,r.jsx)(n.p,{children:"2.1.2 Third: No circumvention of the objectives of Article 123 TFEU"}),"\n",(0,r.jsx)(n.p,{children:'For the third prohibition (prohibition on circumvention), i.e. that "purchases made on the\r\nsecondary market may not be used to circumvent the objective of Article 123 TFEU", the purpose of Article 123 had to be considered.37'}),"\n",(0,r.jsx)(n.p,{children:'In order to identify this purpose, the ECJ relied on a 1991 contribution by the European\r\nCommission in which the Commission had presented proposals for the future rules on Economic and Monetary Union.38 There, with respect to the predecessor provision to Article 123 TFEU, the\r\nCommission stated: "This Article is concerned with the potential threat to monetary stability posed by budget deficits and thei\xdfr financing."39 On this basis, the ECJ attributed to Article 123 TFEU the\r\nobjective of "encourag[ing] the Member States to follow a sound budgetary policy, not allowing monetary financing of public deficits [...] to lead to excessively high levels of debt or excessive\r\nMember State deficits."40 Since the ESCB also has the task of supporting the general economic policies in the Union (Article 127(1), second sentence, TFEU), which include "sound public finances"\r\n(Article 119(3) TFEU), it may not simultaneously undermine this with its monetary policy.41 The prohibition on circumvention would therefore be violated if the bond purchase program were such\r\n"as to lessen the impetus of the Member States concerned to follow a sound budgetary policy."42'}),"\n",(0,r.jsx)(n.p,{children:"Advocate General Pedro Cruz Villaln also stated in his Opinion:43"}),"\n",(0,r.jsx)(n.p,{children:"[218] Article 123 TFEU therefore reflects a very real concern on the part of those who drew up the institutional f\xfcramework for economic and monetary union, which is why it was decided to\r\nintroduce into primary law an absolute prohibition on any forms of financing States which could jeopardise the objectives of fiscal discipline laid down in the Treaties. One of those prohibited\r\nforms is so-called monetary financing, whereby a central bank, the institution with power to issue money, purchases a States debt instruments. It is clear that this form of financing may\r\njeopardise that States ability to meet its financial obligations in the medium and long term, while it may also be a significant source of price inflation. Since a common economic and\r\nmonetary policy presupposes the existence of States with healthy public finances and a policy whose priority is the maintenance of price stability, it is obvious that, in such circumstances, a\r\nmonetary financing mechanism significantly impairs those objectives."}),"\n",(0,r.jsx)(n.p,{children:'The finding that the Unions policies "priority is the maintenance of price stability" is further supported by the Carli Report cited above, which stated: "The aim of that policy will be to ensure\r\nthat the purchasing power of the currency remains stable; measures to support the policy for boosting income and employment would not be ruled out but, in the event of a conflict of interests,\r\nprice stability would have to take precedence."'}),"\n",(0,r.jsx)(n.p,{children:"37"}),"\n",(0,r.jsx)(n.p,{children:"ECJ judgment of 16.6.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:400, para. 98."}),"\n",(0,r.jsx)(n.p,{children:"38"}),"\n",(0,r.jsx)(n.p,{children:"ECJ judgment of 16.6.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:400, para. 100."}),"\n",(0,r.jsx)(n.p,{children:"39"}),"\n",(0,r.jsx)(n.p,{children:"Draft Treaty, Bulletin of the European Communities, Supplement 2/91, p. 54."}),"\n",(0,r.jsx)(n.p,{children:"40"}),"\n",(0,r.jsx)(n.p,{children:"ECJ judgment of 16.6.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:400, paras 100 f. and 109 and Opinion of Advocate General Cruz Villaln"}),"\n",(0,r.jsx)(n.p,{children:"of 14.1.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:7, para. 217."}),"\n",(0,r.jsx)(n.p,{children:"41"}),"\n",(0,r.jsx)(n.p,{children:"ECJ judgment of 16.6.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:400, para. 109 and Opinion of Advocate General Wathelet of 4.10.2018,"}),"\n",(0,r.jsx)(n.p,{children:"C-493/17 - Weiss, ECLI:EU:C:2018:815, para. 50 with further references."}),"\n",(0,r.jsx)(n.p,{children:"42"}),"\n",(0,r.jsx)(n.p,{children:"ECJ judgment of 16.6.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:400, paras 100 f. and 109; ECJ judgment of 11.12.2018 - C-493/17 - Weiss,"}),"\n",(0,r.jsx)(n.p,{children:"ECLI:EU:C:2018:1000, para. 107."}),"\n",(0,r.jsx)(n.p,{children:"43"}),"\n",(0,r.jsx)(n.p,{children:"Opinion of Advocate General Cruz Villaln, 14.1.2015, C-62/14 - Gauweiler, ECLI:EU:C:2015:7, para. 218."}),"\n",(0,r.jsx)(n.p,{children:"15 of 27"}),"\n",(0,r.jsx)(n.p,{children:"Having said this, in her Opinion of March 31, 2022, Advocate General Juliane Kokott expressed matters in a more reserved way, stating that the purpose of the prohibition of monetary financing\r\nis to prevent the governments of the Member States f\xfcrom increasing the monetary base through thei\xdfr fiscal policy decisions and thereby possibly influencing the monetary policy of the ESCB. []\r\nThis is the case even though contrary to widespread belief the monetary policy of the ESCB is not aimed primarily at controlling the monetary base or the money supply, but rather at ensuring\r\nprice stability.44"}),"\n",(0,r.jsx)(n.p,{children:"Conclusion: This interpretation is based on the underlying purposes of the provision. In this context, the ECJ places a particular focus on the soundness of public finances and the threats to price stability that would result f\xfcrom the monetary financing of excessive deficits. However, it is clear\r\nf\xfcrom historical documents that the overarching objective, including for the pursuit of fiscal discipline contrary to thei\xdfr juxtaposition in Article 119(3) TFEU was that of price stability."}),"\n",(0,r.jsx)(n.p,{children:"2.2 BVerfG: Prohibition on circumvention"}),"\n",(0,r.jsx)(n.p,{children:'From the perspective of the German Federal Constitutional Court, the objective of Article 123 TFEU is "to encourage Member States to pursue sound budgetary policies [...] and to prevent excessively\r\nhigh levels of debt or excessive Member State deficits".45 It sees the prohibition on monetary financing as one of the central rules that define the monetary union as a "community of stability"\r\n(Stabilittsgemeinschaft).46 In the Court\'s view, this objective is accordingly also served by a prohibition on circumvention.47 It sees two concrete risks for the German budget:'}),"\n",(0,r.jsx)(n.p,{children:'inflation risks, since the value of money represents the "general economic foundation of budgetary policy",48 and'}),"\n",(0,r.jsx)(n.p,{children:"risks of loss for the Bundesbank due to defaults on government bonds, which the budget would have to compensate or, at any rate, bear (Section 27 No. 2 BBankG).49"}),"\n",(0,r.jsx)(n.p,{children:"44"}),"\n",(0,r.jsx)(n.p,{children:"Opinion of 31.3.2022, C-45/21 - Banka Slovenije, ECLI:EU:C:2022:241, para. 129 and footnote 65 thereof."}),"\n",(0,r.jsx)(n.p,{children:"45"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 154, 17 para. 181 with further references; BVerfGE 146, 216 para. 78."}),"\n",(0,r.jsx)(n.p,{children:"46"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 146, 216; BVerfGE 142, 123 para. 201."}),"\n",(0,r.jsx)(n.p,{children:"47"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 142, 123 para. 198-200; BVerfGE 154, 17 para. 182."}),"\n",(0,r.jsx)(n.p,{children:"48"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 89, 155 (207); BVerfGE 151, 202 para. 134."}),"\n",(0,r.jsx)(n.p,{children:"49"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 146, 216 para. 125 f. with further references; BVerfGE 154, 17 para. 227."}),"\n",(0,r.jsx)(n.p,{children:"16 of 27"}),"\n",(0,r.jsx)(n.p,{children:'In its OMT ruling, the Federal Constitutional Court therefore followed the ECJ and held "[first,] that bonds may not be purchased on the primary market; [second,] that purchases on the secondary\r\nmarket may not give the affected Member States certainty that thei\xdfr bonds will be purchased by the ESCB, and [third,] that the purchase may not relieve the affected Member States of incentives\r\nto conduct sound budgetary policy".50 In its PSPP judgment, Karlsruhe further stated that central banks should not become a "permanent source of finance for the Member States" by buying and\r\nholding a certain share of government debt on a permanent basis, which would then play no role at all in the credit rating of the respective Member State51 ("the relevant sovereign debts would be\r\nneutralised with permanent effect");52 this would remove the incentive for Member States to pursue sound fiscal policies.53 If, when redeeming bonds, the central bank were to continuously\r\nreinvest the amounts collected, the prohibition on monetary financing under Article 123 TFEU would therefore be violated.54'}),"\n",(0,r.jsx)(n.p,{children:"Conclusion: The Federal Constitutional Court placed the focus of Article 123 TFEU directly on budgetary discipline, whereas at the ECJ it had been more oriented teleologically and historically towards the goal of price stability, f\xfcrom which the goal of budgetary discipline was derived. Underlying the BVerfGs focus is the constitutional perspective concerning the budgetary sovereignty of the Bundestag, which may not be threatened by other Member States running unsafe finances\r\nwith the support of the central bank.55 However, here as well, the protective goals for the German budget remain inflation i.e. price stability and risk of loss."}),"\n",(0,r.jsx)(n.p,{children:'2.3 Conclusion: "May contain traces of monetarism"'}),"\n",(0,r.jsx)(n.p,{children:"The assumptions of Sargent and Wallace are thus subtly reflected in the courts interpretation of\r\nArticle 123 TFEU. The ECJ's interpretation that market participants may not act as de facto intermediaries for central banks in primary market-equivalent bond purchases (second\r\nprohibition) and that they must not reduce Member States incentives to pursue sound fiscal policies (third prohibition) aims to ensure that all participants act with caution: Member States in\r\nthei\xdfr spending behaviour, potential primary market buyers in thei\xdfr demand for government bonds, and central banks in thei\xdfr bond purchases. This reflects the fear of fiscal dominance in the\r\npresence of elevated levels of government debt, which in the minds of Sargent and Wallace would lead to monetary financing (Assumption 2), an increase in the central bank money supply and,\r\nconsequently, inflation. In the courts jurisprudence, the third assumption of Sargent and Wallace\r\n(that yields are independent of interest rate expectations on the basis of the supply and demand for capital) has become a normative requirement for the formation of market prices for\r\nin which central banks are not allowed (or allowed only under narrow government bonds,\r\nconditions) to intervene through bond purchases.56"}),"\n",(0,r.jsx)(n.p,{children:"50"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 142, 123 para. 199."}),"\n",(0,r.jsx)(n.p,{children:"51"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 154, 17 para. 195."}),"\n",(0,r.jsx)(n.p,{children:"52"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 146, 216 para. 98."}),"\n",(0,r.jsx)(n.p,{children:"53"}),"\n",(0,r.jsx)(n.p,{children:"54"}),"\n",(0,r.jsx)(n.p,{children:"55"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 134, 366 para. 43."}),"\n",(0,r.jsx)(n.p,{children:"56"}),"\n",(0,r.jsx)(n.p,{children:"See Orphal, Marktlogik ist kein Rechtsgebot, VerfBlog of Aug. 2, 2022 (DE) and the same in Politik & konomie, Aug. 16, 2022. (DE)"}),"\n",(0,r.jsx)(n.p,{children:"17 of 27"}),"\n",(0,r.jsx)(n.p,{children:"A non-monetarist interpretation of Article 123 TFEU"}),"\n",(0,r.jsx)(n.p,{children:"On the basis of the case law described above, this section draws out the implications for the interpretation of Article 123 TFEU f\xfcrom the fact that monetarism is now considered obsolete in\r\nacademia and among central bank practitioners worldwide. In doing so, we find that dropping the notion of a money multiplier also shifts the relationship that bond purchases (3.1) and fiscal dominance in the sense of Sargent and Wallace (3.2) have to price stability. As a result, there is a need\r\nfor a new interpretation of the prohibition on monetary financing under Article 123 TFEU, which historically assumed economic relationships that have since been refuted (3.3)."}),"\n",(0,r.jsx)(n.p,{children:"3.1 Money supply and price stabilityfi"}),"\n",(0,r.jsx)(n.p,{children:"The central purpose of Article 123 TFEU is recognised to be the objective of guarding price stability against the risk that the government's access to central bank financing might increase the\r\nmoney supply and thereby jeopardise \"monetary stability\". This relates to Sargent and Wallace's concern that monetary financing increases the central bank money supply, which in turn raises the\r\n(commercial) bank money supply, which in turn would increase inflation. The result would be a loss of central bank control over inflation."}),"\n",(0,r.jsx)(n.p,{children:"According to todays understanding of monetary policy transmission, this relationship does not hold. Prices rise because of a reduction in supply or an increase in demand, not because of an\r\nincrease in the central bank or commercial bank money supply. Central banks do not use thei\xdfr monetary policy instruments (short-term interest rates, forward guidance, bond purchase\r\nprograms) to control the money supply, however defined, but to control the financing conditions of households, companies and governments, and especially the interests rates they face as\r\nborrowers and lenders. Accordingly, monetary financing, including bond purchases by central banks, does not automatically generate an increase in demand (there is no money creation\r\nmultiplier).57 If demand is not automatically increased by an increase in the money supply, however, then an increase in the money supply, e.g. through bond purchases be it on the primary\r\nmarket or on the secondary market does not in itself imply an increase in demand and thus (a risk of) inflation.58"}),"\n",(0,r.jsx)(n.p,{children:"This changes a central presupposition behind the prohibition on monetary financing.\r\nInflation can still pose a threat where monetary financing is concerned, namely through increased government demand (if the additional government spending does not expand supply and/or is not\r\noffset by a sufficient reduction in demand, for instance, through increased taxes or other demandreduction measures such as lending-reducing bank regulations). In such a constellation, aggregate demand would rise, and inflation may follow."}),"\n",(0,r.jsx)(n.p,{children:"57"}),"\n",(0,r.jsx)(n.p,{children:"See above 1.3 and Kern/Sigl-Gl\xfcckner/Krah, Monetary Targeting revisited, May 31, 2022, p. 5."}),"\n",(0,r.jsx)(n.p,{children:"58"}),"\n",(0,r.jsx)(n.p,{children:"Monetary policy bond purchase programs do not work by increasing the money supply but by influencing financing conditions (including"}),"\n",(0,r.jsx)(n.p,{children:"maturity and risk premia), cf. Kern, Das Anti-Fragmentierungstool des Eurosystems verstndlich erkl\xe4rt, Geldbrief, July 7, 2022. (DE)"}),"\n",(0,r.jsx)(n.p,{children:"18 of 27"}),"\n",(0,r.jsx)(n.p,{children:'However, this no longer follows f\xfcrom the historical understanding in which inflation resulted f\xfcrom an increase in the money supply, but f\xfcrom a lack of balancing out the increase in demand in a\r\ncontext where the economy is running at full capacity. Most importantly, in the latter case, the central bank responds to an inflationary increase in demand by activating its instruments\r\nespecially the policy rate(s) and tightening financing conditions. The possible fear that central banks might ref\xfcrain f\xfcrom tightening out of deference to heavily-indebted Member States, in turn,\r\ndoes not depend on whether the creditors of the Member States are the central banks or private market participants. The prohibition on monetary financing does not prevent this form of\r\n"consideration". An increase in interest rates will curb inflation regardless of who is driving demand and who the state\'s creditors are. It slows down investment activity and consumer\r\nspending in the economy as a whole, tightens the financing conditions for all market participants and, as a result, may also drive the lowest-ranking actors into insolvency.59 Whether such\r\n"crowding out" by the state is desirable is a political question but it is no longer a question of inflation. And only the question of inflation is the subject of the ESCBs primary mandate.'}),"\n",(0,r.jsx)(n.p,{children:"A corresponding non-monetarist understanding, in which the central bank does not aim for control over the money supply, but instead manages financing conditions with an eye on\r\naggregate demand, is reflected in the monetary policy strategies pursued by central banks today.\r\nIn both the ESCB and the Fed, the key interest rate corresponds to the deposit rate paid by central banks on balances held by commercial banks at the central bank. For the central bank to be able\r\nto control interest rates in this way, central bank money must never run short; otherwise, the effective short-term interest rate risks rising above the central bank's desired policy rate.\r\nAccordingly, in the monetary policy strategy of central banks today, there is no maximum limit for central bank money, but only a minimum limit (below which monetary policy would be curtailed in\r\nits effect, as interest rates on the market would then rise above the level desired by monetary policy).60"}),"\n",(0,r.jsx)(n.p,{children:"Article 123 TFEU therefore does not have to be interpreted extensively, i.e. beyond the explicitly mentioned prohibition of primary market purchases, at least not on the gro\xdfunds of avoiding\r\ninflation."}),"\n",(0,r.jsx)(n.p,{children:"3.2 Fiscal dominance and price stabilityfi"}),"\n",(0,r.jsx)(n.p,{children:"According to some authors, Article 123 TFEU is also intended to protect the independence of central banks so that they cannot come under pressure to finance Member State deficits.61 The\r\nECB, too, has implied this in one of its statements.62 This reflects, in the tradition of Sargent and\r\nWallace, a fear of fiscal dominance,63 in which central banks might become unable to maintain price stability because they would be forced to keep increasing the money supply."}),"\n",(0,r.jsx)(n.p,{children:"59"}),"\n",(0,r.jsx)(n.p,{children:"60"}),"\n",(0,r.jsx)(n.p,{children:"cf. Kern/Sigl-Gl\xfcckner/Krah, Monetary Targeting revisited, p. 11 ff."}),"\n",(0,r.jsx)(n.p,{children:"61"}),"\n",(0,r.jsx)(n.p,{children:"cf. Schnabel, The shadow of fiscal dominance: Misconceptions, perceptions and perspectives, SUERF Policy Note No. 198, October 2020.;"}),"\n",(0,r.jsx)(n.p,{children:"Hde in: Calliess/Ruffert, EUV/AEUV, 6th ed. 2022, Art. 123 TFEU para. 5 with further references (DE); Tutsch in: von der Gro\xdfeben/Schwarze/Hatje, Europisches Unionsrecht, 7th ed. 2015, Art. 123 para. 6-8 (DE); in this sense also BVerfGE 154, 17 para. 161."}),"\n",(0,r.jsx)(n.p,{children:"62"}),"\n",(0,r.jsx)(n.p,{children:"ECB, Opinion on a draft European Council Decision amending Article 136 of the Treaty on the Functioning of the European Union with"}),"\n",(0,r.jsx)(n.p,{children:"regard to a stability mechanism for Member States whose currency is the euro, CON/2011/24, OJ. EC C 140 v. 11.5.2011, p. 8, note 9."}),"\n",(0,r.jsx)(n.p,{children:"63"}),"\n",(0,r.jsx)(n.p,{children:"cf. BVerfGE 154, 17 para. 175."}),"\n",(0,r.jsx)(n.p,{children:"19 of 27"}),"\n",(0,r.jsx)(n.p,{children:"First, however, based on what we know today, fiscal dominance in the sense coined by Sargent and\r\nWallace would not prevent the central bank f\xfcrom pursuing price stability, since aggregate demand is controlled through interest rates and not the money supply."}),"\n",(0,r.jsx)(n.p,{children:"Second, this concern has also been addressed through ensuring the independence of the ESCB\r\n(Article 130 TFEU). So far, there is no reason to doubt that its legally-secured independence is anything less than ironclad in practice.64 To the extent that the ESCB considers the purchase of\r\ngovernment bonds necessary for monetary policy purposes, banning or restricting such purchases therefore appears not only to obstruct the pursuit of its inflation target;\r\nit also seems disproportionate to place an unjustifiable distrust of the actual preservation of its independence\r\nabove the effective pursuit of its price stability objective."}),"\n",(0,r.jsx)(n.p,{children:'To elaborate on this point: neither at the time of the founding of the European Union, nor at any later point, has there ever been any serious reason to doubt the independence of the ECB. The\r\nECBs actions in the face of the economic turbulence in the euro area during and after the financial crisis, the Eurozone sovereign debt crisis, the COVID-19 crisis and now in the context of the Russian\r\nwar on Ukraine have, of course, led to doubts among some about the ESCB\'s de facto\r\nindependence; however, neither the BVerfG nor the media were able to determine whether the\r\nECB was acting too independently ("insufficient democratic and judicial control") or not independently enough ("fiscal dominance"). It is conceivable that this reflects a fundamental\r\nproblem for the democratic legitimacy of independent institutions.65 However, since the actions of the Bundesbank have never given rise to the same lack of trust at least not in Germany the\r\nvoicing of this distrust by German commentators could also be seen as an expression of potential cultural prejudices. Be that as it may: there are no factual gro\xdfunds for this suspicion, especially\r\nconsidering the fact that Eurozone inflation has long been below its inflation target.66 Similarly,\r\nArticle 123 TFEU does not prohibit the reduction (or increase) of key interest rates as a safeguard against an ECB ignoring its mandate, which has an even more dramatic effect on government\r\ninterest burdens than increased (or reduced) bids in bond auctions.67 Any remaining distrust in the\r\nECB\'s de facto independence has therefore and fortunately so, for the price- and economic stability of the euro area been codified only to an inconsequential extent.'}),"\n",(0,r.jsx)(n.p,{children:"64"}),"\n",(0,r.jsx)(n.p,{children:"See also Neumeier in: Hufeld/Ohler, Enzyklopdie Europarecht, vol. 9 (1st ed. 2022), 10 para. 59 f. (DE)"}),"\n",(0,r.jsx)(n.p,{children:"65"}),"\n",(0,r.jsx)(n.p,{children:"Paul Tucker in his book Unelected Power: The Quest for Legitimacy in Central Banking and the Regulatory State (2018), p. 94, could be"}),"\n",(0,r.jsx)(n.p,{children:'understood in this sense: "[...] the catalog of realist motivations is hardly conducive to producing enduring legitimacy. Even if political'}),"\n",(0,r.jsx)(n.p,{children:"scientists are correct empirically, that does not mean that the resulting structures are sustainable or conducive to trust in government."}),"\n",(0,r.jsx)(n.p,{children:"[...] When it comes to constitutional politics and so to the distribution of government power, realism that does not look beyond the day"}),"\n",(0,r.jsx)(n.p,{children:'after tomorrow is a cousin of roulette, as various Western democracies might currently be rediscovering in the reaction against technocracy." This work is also cited by the BVerfG (BVerfGE 151, 202 para. 131).'}),"\n",(0,r.jsx)(n.p,{children:"66"}),"\n",(0,r.jsx)(n.p,{children:"In view of the proven easing effects of bond purchases on general financing conditions, which increase inflation, it is unconvincing to"}),"\n",(0,r.jsx)(n.p,{children:"counter that the measures were not intended to increase inflation but to provide financial assistance to Member States. See Kern, Das"}),"\n",(0,r.jsx)(n.p,{children:"Anti-Fragmentierungstool des Eurosystems verstndlich erkl\xe4rt, Geldbrief, July 7, 2022 (DE) and Deutsche Bundesbank, Sectoral Portfolio Adjustments in the Euro Area in the Low Interest Rate Phase, Monthly Bulletin April 2020, p. 19 ff. (27); Congressional Budget Office,"}),"\n",(0,r.jsx)(n.p,{children:"How the Federal Reserve's Quantitative Easing Affects the Federal Budget, September 2022."}),"\n",(0,r.jsx)(n.p,{children:"67"}),"\n",(0,r.jsx)(n.p,{children:"Pursuant to No. 5 sentences 1 and 4 of the Auction rules for the issue of German federal securities, as amended on January 1, 2021,"}),"\n",(0,r.jsx)(n.p,{children:"which apply in the tender procedure in accordance with section 1 sentence 2 of the Issuance terms and conditions for Federal bonds,"}),"\n",(0,r.jsx)(n.p,{children:"five-year Federal notes, Federal Treasury notes and Treasury discount paper of the German Government, as amended in December"}),"\n",(0,r.jsx)(n.p,{children:"2012, bids may be submitted with or without the indication of a bid price or at different prices. That the interest rate is determined by"}),"\n",(0,r.jsx)(n.p,{children:"supply and demand (according to Advocate General Cruz Villaln in his Opinion of 14 January 2015, C-62/14 - Gauweiler,"}),"\n",(0,r.jsx)(n.p,{children:"ECLI:EU:C:2015:7, para. 222) is correct in that a low-interest bond will be purchased at a lower price (as a percentage of the nominal"}),"\n",(0,r.jsx)(n.p,{children:"amount, No. 5 sentence 1 of the Auction rules for the issue of German federal securities)."}),"\n",(0,r.jsx)(n.p,{children:"20 of 27"}),"\n",(0,r.jsx)(n.p,{children:'The strictest possible ban on bond purchases is therefore not necessary based on concerns about fiscal dominance, either. Increasing the money supply would not have an inflationary\r\neffect, as the central bank maintains control over interest rates. The ECB and the other central banks of the ESCB are independent. Providing additional "safeguards" to this independence by\r\nprohibiting them f\xfcrom using an important monetary policy instrument only harms the effective realisation of thei\xdfr mandate.'}),"\n",(0,r.jsx)(n.p,{children:"3.3 Significance for the interpretation of Article 123 TFEU"}),"\n",(0,r.jsx)(n.p,{children:"The wording of Article 123 TFEU prohibits primary market purchases. With respect to price stability and the general objective of sound public finances (Article 119(3) TFEU), an extensive interpretation\r\nof the article is not necessary based on what we know now about the causes of inflation; on the contrary, the current state of knowledge would warrant a narrower interpretation. Based on\r\ncurrent understanding, the cause of inflation (deflation) is not an expansion (contraction) of the monetary base, but a strengthening (weakening) of demand, or a contraction (expansion) of\r\nsupply. Concerning demand management through monetary policy, if an additional strengthening of demand at the effective interest rate floor68 cannot be achieved by a further reduction in shortterm interest rates, bond purchase programs are now regarded as established monetary policy\r\ninstruments with the aim of achieving a reduction in term premia and thus in long-term interest rates (see above Figure 1). Prohibiting central banks f\xfcrom using this instrument would constitute a\r\nsevere restriction of thei\xdfr room for manoeuvre. This works against both price stability and, by damaging economic stability, sound public finances."}),"\n",(0,r.jsx)(n.p,{children:'An updated interpretation of the prohibition should be guided by Article 123s underlying purpose, while also recalling that "sound public finances" as a general economic policy objective of the\r\nUnion is defined neither by particularly high interest rates nor by f\xfcrugal spending behaviour, since the soundness of public finances depends on many other factors, the assessment of which has\r\nprimarily been entrusted not to law but to politics (Articles 121 and 126 para. 2 ff. and para. 10\r\nTFEU).69 That the recognition of this fact reduces the weight of Article 123 TFEU and thus of the judicial review of monetary policy measures, and that in its place, the precepts of the primary and\r\nsecondary mandate of the ESCB come to the foref\xfcront, is to be welcomed in view of the fact that the article may be considered historically outdated.'}),"\n",(0,r.jsx)(n.p,{children:"68"}),"\n",(0,r.jsx)(n.p,{children:'cf. Benot Cur, "How binding is the zero lower boundfi" speech f\xfcrom May 18, 2015. The then-member of the ECB\'s Governing Council'}),"\n",(0,r.jsx)(n.p,{children:"explains in this speech how the existence of an effective interest rate floor below the zero lower bound implies the need for an increased"}),"\n",(0,r.jsx)(n.p,{children:"use of bond purchase programs."}),"\n",(0,r.jsx)(n.p,{children:"69"}),"\n",(0,r.jsx)(n.p,{children:"See also Orphal and Krah forthcoming, Sound public finances."}),"\n",(0,r.jsx)(n.p,{children:"21 of 27"}),"\n",(0,r.jsx)(n.p,{children:"Box 2: The Federal Constitutional Court and the budgetary right of the Bundestag"}),"\n",(0,r.jsx)(n.p,{children:"The protective purpose assigned by the BVerfG to Art. 123 TFEU in order to avert risks to the\r\nGerman budget70 is subject to its own erroneous assumptions, which must be addressed specifically."}),"\n",(0,r.jsx)(n.p,{children:"The BVerfG urges a narrow interpretation of the ESCB's powers in order to rule out risks to the German budget that could arise, for instance, if the Bundesbank were to incur losses\r\nf\xfcrom bond purchase programs when bonds default. In this Box 2, we explain that there are no risks to the federal budget f\xfcrom bond purchases by Eurosystem central banks beyond\r\nthose generally in\xe4herent to participation in a monetary union and that Article 123 TFEU should therefore not be instrumentalised to prevent these general risks.71 These risks should\r\nbe taken seriously, but protection against them should be based on the legal standards that have been created for this purpose: Articles 121, 125 and 126 TFEU."}),"\n",(0,r.jsx)(n.p,{children:"Since the beginning of the PSPP, government bonds have been purchased exclusively by thei\xdfr own national central banks. If, for example, the Austrian government were to default\r\non its bonds, there would be no direct loss for the Deutsche Bundesbank, but only for the\r\nAustrian National Bank."}),"\n",(0,r.jsx)(n.p,{children:"Indirect losses by the Bundesbank would be conceivable in a scenario in which the Austrian\r\nNational Bank defaults on its TARGET liabilities.72 Such liabilities may arise, for example, if the\r\nAustrian National Bank purchases government bonds f\xfcrom a German commercial bank or if the seller subsequently transfers the bank deposits received to an account at a German\r\ncommercial bank: in both cases, the credit balance of a German commercial bank with the\r\nBundesbank would increase.73 For the Bundesbank, this creates a liability vis--vis the respective commercial bank.74 In return, the Bundesbank receives a TARGET claim against the\r\nECB and the ECB receives a claim against the Austrian National Bank.75 In the event that a default on Austrian government bonds was followed by a default of the Austrian National\r\nBank, the ECB could suffer losses accordingly. These losses would have to be borne jointly by the central banks in the Eurosystem according to the ECB capital key (Article 33.2 of the\r\nStatute of the ESCB)."}),"\n",(0,r.jsx)(n.p,{children:"70"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 146, 216 para. 68 with further references."}),"\n",(0,r.jsx)(n.p,{children:"71"}),"\n",(0,r.jsx)(n.p,{children:'See Steinbach in: Hufeld/Ohler, Enzyklopdie Europarecht, vol. 9 (1st ed. 2022), 6 para. 74 f. (DE): "Until the 1990s, it was not debt that'}),"\n",(0,r.jsx)(n.p,{children:'was considered the primary cause of destabilisation, but inflation. The phenomena of the sovereign debt crises are, for Europe, a comparatively recent issue"; see also General Court judgment of 9.2.2022, T-868/16, ECLI:EU:T:2022:58, para. 96; Cruz Villaln Opinion of'}),"\n",(0,r.jsx)(n.p,{children:"14.1.2015, C-62/14 (Gauweiler), ECLI:EU:C:2015:7, para. 219; ECJ judgment of 27.11.2012, C-370/12 (Pringle), ECLI:EU:C:2012:756, para."}),"\n",(0,r.jsx)(n.p,{children:"135; Hufeld in: Hatje/Mller-Graff, Enzyklopdie Europarecht, vol. 4 (2nd ed. 2021), section 24 para. 8 (DE): \"The guarantee and stabilization law, especially the budgetary law of 'sound public finances' (Article 119(3) TFEU), does not consolidate a series of ends in themselves."}),"\n",(0,r.jsx)(n.p,{children:'Certainly objective law, it [...] runs on the peace, values and welfare policy of a European economic policy committed to f\xfcreedom [...]";'}),"\n",(0,r.jsx)(n.p,{children:"same wording Hufeld/Repasi in: Hufeld/Ohler, Enzyklopdie Europarecht, vol. 9 (1st ed. 2022), section 8 para. 8. (Translation by the authors). (DE)"}),"\n",(0,r.jsx)(n.p,{children:"72"}),"\n",(0,r.jsx)(n.p,{children:"On the functioning of the TARGET2 system at a glance. ECB, What is TARGET2fi, 29.6.2016."}),"\n",(0,r.jsx)(n.p,{children:"73"}),"\n",(0,r.jsx)(n.p,{children:"Annex II to Guideline ECB/2012/27 on a Trans-European Automated Real-time Gro\xdfss settlement Express Transfer system, Art. 12 and"}),"\n",(0,r.jsx)(n.p,{children:"Annex IIa ibid, Art. 12."}),"\n",(0,r.jsx)(n.p,{children:"74"}),"\n",(0,r.jsx)(n.p,{children:"Annex IV to Guideline (EU) 2016/2249 on the legal f\xfcramework for accounting and reporting in the European System of Central Banks"}),"\n",(0,r.jsx)(n.p,{children:"(ECB/2016/34), Liabilities, item 2."}),"\n",(0,r.jsx)(n.p,{children:"75"}),"\n",(0,r.jsx)(n.p,{children:"Article 6(2) of Guideline ECB/2012/12 and Annex IV to Guideline ECB/2016/34, Assets, item 9.5 and Liabilities, item 10.4."}),"\n",(0,r.jsx)(n.p,{children:"22 of 27"}),"\n",(0,r.jsx)(n.p,{children:'However, this case is not foreseen in the regulation on TARGET2 balances (Article 6 para. 2 of Guideline ECB/2012/27): by definition, a central bank does not become insolvent in its own\r\ncurrency unless this follows an explicit decision to do so. TARGET balances are central banks wealth; in the Eurozone, central banks capital increases are made by increasing thei\xdfr TARGET liabilities accordingly (and increasing thei\xdfr participating interest in the ECB in the same\r\namount). Rather, the amount required for the capital increase is in fact created by money creation.76 In this respect, the question arises as to whether the crediting of TARGET2 balances is still a matter of "claims", or whether it is not already money itself or simply a balancing\r\nitem.77 In 1973, for example, the Bundesbank had negative equity of almost 7 billion German\r\nMarks, which it reported as a "balance sheet loss".78 Former Bundesbank President Schlesinger made the following comments in an essay in the Bundesbank staff periodical:'}),"\n",(0,r.jsx)(n.p,{children:'"From a purely legal point of view, the Bundesbank was over-indebted because the loss carry-forwards significantly exceeded its equity capital. Although we had a negative balance, we were not insolvent because we were ultimately able to print the money ourselves. In the\r\nCentral Bank Council, we discussed whether the government should pay for the losses. [...]\r\nWe ref\xfcrained f\xfcrom doing so. But the bottom line, of course, was that the government shared the cost because we didn\'t transfer profits to the federal government for a number of years\r\nuntil the loss carry-forward had been ablated."'}),"\n",(0,r.jsx)(n.p,{children:"Even if the Bundesbank were to incur a loss, there would be no constitutional obligation to make additional contributions to the federal budget. Money is created at the central bank.\r\nThe federal government's obligation under Article 88 of the Basic Law to establish a monetary and central bank is not a financial one, but an institutional one;79 the federal government must ensure the Bundesbank's ability to function, not its financing balance.80"}),"\n",(0,r.jsx)(n.p,{children:'The federal budget would thus only be threatened with an imputed loss in the form of lost profits if it were explicitly decided that another national central bank would now no longer\r\nfulfil its obligations vis--vis the Eurosystem (i.e. that TARGET2 balances would no longer be settled). In this case, too, the only loss to the federal budget would be the lost Bundesbank\r\nprofit (section 27 no. 2 BBankG), which would be reduced proportionately in relation to the\r\nECB capital key. However, the Member States consciously assumed this risk in the event of a breakup of the monetary union when they entered into a monetary union in the first place:\r\nas early as 1990, the Bundesbank emphasised that the participating economies would be\r\n"inextricably linked to one another in the monetary field, come what may."81'}),"\n",(0,r.jsx)(n.p,{children:"76"}),"\n",(0,r.jsx)(n.p,{children:"Opinion of Advocate General Juliane Kokott f\xfcrom 31.3.2022, C-45/21 - Banka Slovenije, ECLI:EU:C:2022:241, paras 61 ff., 62."}),"\n",(0,r.jsx)(n.p,{children:"77"}),"\n",(0,r.jsx)(n.p,{children:"On this Sahr, Between Duties and Fictions: The Political Dimension of the Euro f\xfcrom the Perspective of a Relationist Sociology of Money,"}),"\n",(0,r.jsx)(n.p,{children:"Zeitschrift f\xfcr Soziologie Vol. 48 No. 3 (2019), p. 209 ff."}),"\n",(0,r.jsx)(n.p,{children:"78"}),"\n",(0,r.jsx)(n.p,{children:"Annual Report of the Deutsche Bundesbank, 1973, p. 82. (DE)"}),"\n",(0,r.jsx)(n.p,{children:"79"}),"\n",(0,r.jsx)(n.p,{children:"See on this topic Remmert in: Epping/Hillgruber, BeckOK GG, 51st ed. as of 15.5.2022, Art. 88 para. 2 f. (DE)"}),"\n",(0,r.jsx)(n.p,{children:"80"}),"\n",(0,r.jsx)(n.p,{children:"See Ohler in: Schmidt-Bleibtreu/Hofmann/Hennecke, Grundgesetz, 15th ed. 2022, Art. 88 para. 6. (DE)"}),"\n",(0,r.jsx)(n.p,{children:"81"}),"\n",(0,r.jsx)(n.p,{children:"German Bundesbank Monthly Report, October 1990, p. 4."}),"\n",(0,r.jsx)(n.p,{children:"23 of 27"}),"\n",(0,r.jsx)(n.p,{children:'The BVerfG took a similar view in a 2014 ruling. According to the court, the complainants had\r\n"not shown how and to what extent the implementation of the TARGET2 system could impair the overall budgetary responsibility of the German Bundestag [...]."82 Nor had it been explained "why the formation of balances is tantamount to a liability mechanism [...] and how and\r\nto what amount liability risks arise to the Federal Republic of Germany" or how "the existing\r\nTARGET2 balances considerably impair the Federal Republic of Germanys decision-making power, for instance with regard to exiting the euro currency area."83 The idea that, after such\r\nstatements, it would now identify a threat to overall fiscal responsibility f\xfcrom TARGET2 balances in the case of bond purchases by itself, would at a minimum, be surprising.'}),"\n",(0,r.jsx)(n.p,{children:"Against this backgro\xdfund, the role of Article 123 TFEU is clearly not to minimise hypothetical risks of loss for the federal budget in the event of the breakup of the monetary union, but to\r\nensure price stability. It should therefore not be interpreted in a way that runs counter to its actual purpose of achieving price stability in the name of the Bundestag's budgetary right."}),"\n",(0,r.jsx)(n.p,{children:"The Federal Constitutional Court understandably attempts to specify the limits of the ESCB's mandate in order to prevent a creeping transfer of competences to the European level.84 The court\r\nalso understandably tries within the legal f\xfcramework to exclude risks for the German budget.85\r\nHowever, this objective cannot be convincingly achieved by means of a particularly strict and expansive interpretation of the prohibition on primary market purchases (Article 123 TFEU), as we\r\nexplain in Box 2. The objective of Article 123 TFEU is to ensure price stability, the achievement of which is made more difficult by an extensive interpretation. Instead of interpreting Article 123\r\nTFEU contrary to its own purpose, the protection of the German budget should be pursued through Articles 121, 125 and 126, which were expressly provided for this purpose."}),"\n",(0,r.jsx)(n.p,{children:"With reference to the prohibitions developed in the case law, a non-monetarist interpretation of\r\nArticle 123 TFEU has the following implications:"}),"\n",(0,r.jsx)(n.p,{children:"The ECJ's second prohibition, which prohibits action with an equivalent effect to primary market purchases (such as secondary market purchases explicitly communicated to\r\nprimary market purchasers in advance), should be discarded. It does not advance the purposes of Article 123. It can only serve these purposes coincidentally, and otherwise only\r\ndo harm."}),"\n",(0,r.jsx)(n.p,{children:"82"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 135, 317 para. 139."}),"\n",(0,r.jsx)(n.p,{children:"83"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 135, 317 para. 140."}),"\n",(0,r.jsx)(n.p,{children:"84"}),"\n",(0,r.jsx)(n.p,{children:"BVerfGE 154, 17 para. 103 f., 105 ff.; especially clear in ibid. para. 140, 142 f. cf. the delineation of economic and monetary policy."}),"\n",(0,r.jsx)(n.p,{children:"85"}),"\n",(0,r.jsx)(n.p,{children:"See above footnote 68 and BVerfGE 154, 17 para. 222 ff."}),"\n",(0,r.jsx)(n.p,{children:"24 of 27"}),"\n",(0,r.jsx)(n.p,{children:'The third prohibition of the ECJ, according to which the objective pursued by Article 123\r\nTFEU must not be circumvented by secondary market purchases (prohibition on circumvention), would have to be developed further on the basis of an open understanding of\r\n"sound" public finances. It is correctly oriented towards the purpose of the standard.\r\nHowever, its original purpose of preventing increases of the money supply to prevent inflation has now been refuted in its causality. A second purpose is seen by the ECJ in the pursuit of sound public finances with, again, the overriding objective of price stability. In\r\nthe hierarchy of objectives of Article 123 TFEU, sound public finances serve to ensure price stability. On this basis, the appropriate question to ask of bond purchases on the\r\nsecondary market is whether they serve the objective of price stability. If it is the case, ancillary objectives such as economic policy coordination and fiscal discipline should not\r\nbe set in opposition to the pursuit of price stability by central banks, but should be enforced according to thei\xdfr own rules (Articles 121 and 126 TFEU).'}),"\n",(0,r.jsx)(n.p,{children:"The Federal Constitutional Court should let go of tying the protection of the Bundestag's budgetary responsibility to Article 123 TFEU, through which it has derived ever more\r\ndetailed requirements and prohibitions. That was never the purpose of Article 123. Its purpose was to prohibit monetary financing out of fear of the inflationary effects of an\r\nexpansion of the money supply. In its current interpretation by the Federal Constitutional\r\nCourt, however, Article 123 TFEU unnecessarily limits the room for manoeuvre of monetary policy and thus potentially prevents the achievement of price stability. A reinterpretation in our sense would not weaken the protection of the Bundestag's budgetary\r\nsovereignty. On the contrary, we maintain that the Bundestags budgetary right should continue to be protected, but that this protection should be based on those legal benchmarks that were actually created for this purpose: Articles 121, 125 and 126 TFEU."}),"\n",(0,r.jsx)(n.p,{children:"25 of 27"}),"\n",(0,r.jsxs)(n.ol,{start:"4",children:["\n",(0,r.jsx)(n.li,{}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"Conclusion"}),"\n",(0,r.jsx)(n.p,{children:"The understanding of economic relationships changes over time. Rules and regulations, once written, do not until and unless they are formally changed."}),"\n",(0,r.jsx)(n.p,{children:"The Maastricht Treaty contains various objectives, the macroeconomic foundations and\r\n(contemporary) presuppositions of which are reflected in the chapter on Economic and Monetary\r\nUnion. The instruments chosen to pursue these goals were influenced by contemporary assumptions about how the economy works."}),"\n",(0,r.jsx)(n.p,{children:"While the goals stay the same price stability, sound public finances and the protection of Member\r\nState budgets , our understanding of how the economy works has changed. We now know monetarism to be a false description of the world. It is the task of jurisprudence to integrate such\r\nchanges into the interpretation of the relevant rules."}),"\n",(0,r.jsx)(n.p,{children:"inflation through\r\nCentral banks around the world have abandoned the attempt to control controlling the money supply. Article 123 TFEU persists. However,\r\njurisprudence offers the possibility to reflect these advancements in economic knowledge within the law as well. This\r\nrequires acknowledging that economic interrelationships are not only the subject of economic theory, but are also the subject of law in Article 123 TFEU and its interpretation. What is needed\r\ntoday is therefore a new interpretation of the prohibition on monetary financing: a nonmonetarist interpretation of Article 123 TFEU."}),"\n",(0,r.jsx)(n.p,{children:"26 of 27"}),"\n",(0,r.jsx)(n.p,{children:"\fDezernat Zukunft is a non-partisan policy institute that aims to explain and re-think monetary, fiscal, and economic policy in an\r\naccessible and coherent way. In doing so, we are guided by our core values:\r\nDemocracy, Dignity, and universal Prosperity."}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.a,{href:"http://www.dezernatzukunft.org",children:"www.dezernatzukunft.org"})}),"\n",(0,r.jsx)(n.p,{children:"@DezernatZ"}),"\n",(0,r.jsx)(n.p,{children:"This work is supported by the European Climate Foundation, Franziskaund-Otto-Bennemann Foundation and Open Philanthropy."}),"\n",(0,r.jsx)(n.p,{children:"Impressum"}),"\n",(0,r.jsxs)(n.p,{children:["Published by:\r\nDezernat Zukunft e.V.,\r\nTieckstrae 37, 10115 Berlin ",(0,r.jsx)(n.a,{href:"http://www.dezernatzukunft.org",children:"www.dezernatzukunft.org"})]}),"\n",(0,r.jsx)(n.p,{children:"Representative of the Board\r\nDr. Maximilian Krah"}),"\n",(0,r.jsx)(n.p,{children:"Members Board:\r\nDr. Maximilian Krah, Dr. Maximilian Paleschke, Nicolas Gassen"}),"\n",(0,r.jsx)(n.p,{children:"Register of Associations of the District Court of Charlottenburg\r\nAssociation register number 36980 B\r\nResponsible for content according to 18 MstV: Dr. Maximilian Krah"}),"\n",(0,r.jsxs)(n.p,{children:["Publisher:\r\nDr. Maximilian Krah, Hamburg\r\nE-Mail: ",(0,r.jsx)(n.a,{href:"mailto:max.krahe@dezernatzukunft.org",children:"max.krahe@dezernatzukunft.org"})]}),"\n",(0,r.jsx)(n.p,{children:"Design:\r\nBurak Korkmaz"}),"\n",(0,r.jsx)(n.p,{children:"This content is licensed by Dezernat Zukunft under CC BY-NC 4.0\r\nContent may be used with clear attribution to the source and, where noted, the author(s)."}),"\n",(0,r.jsx)(n.p,{children:"."}),"\n",(0,r.jsx)(n.p,{children:"27 of 27"}),"\n",(0,r.jsx)(n.p,{children:"InstituteforMacrofinance"})]})}function d(e={}){let{wrapper:n}={...(0,o.R)(),...e.components};return n?(0,r.jsx)(n,{...e,children:(0,r.jsx)(l,{...e})}):l(e)}},28453(e,n,t){t.d(n,{R:()=>a,x:()=>s});var i=t(96540);let r={},o=i.createContext(r);function a(e){let n=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function s(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:a(e.components),i.createElement(o.Provider,{value:n},e.children)}}}]);